import{_ as t,o as d,c as o,ag as a}from"./chunks/framework.BCNEhLBE.js";const p=JSON.parse('{"title":"API Reference","description":"","frontmatter":{"sidebar":false},"headers":[],"relativePath":"api/index.md","filePath":"api/index.md","lastUpdated":1773594226000}'),n={name:"api/index.md"};function r(s,e,c,i,l,h){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="api-reference" tabindex="-1">API Reference <a class="header-anchor" href="#api-reference" aria-label="Permalink to &quot;API Reference&quot;">​</a></h1><h2 id="elenajs-core" tabindex="-1"><code>@elenajs/core</code> <a class="header-anchor" href="#elenajs-core" aria-label="Permalink to &quot;`@elenajs/core`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Elena</code></td><td><code>Elena(superClass)</code></td><td>Creates an Elena component base class. Pass in <code>HTMLElement</code> to get started. Configure the component using static <a href="#component-options">component options</a> on the returned class.</td></tr><tr><td><code>ElenaEvent</code></td><td><code>new ElenaEvent(type, init?)</code></td><td>Extends the native <code>Event</code> with <code>bubbles: true</code> and <code>composed: true</code> already set. Use this to fire custom events from inside a component.</td></tr></tbody></table><h3 id="template-utilities" tabindex="-1">Template Utilities <a class="header-anchor" href="#template-utilities" aria-label="Permalink to &quot;Template Utilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>html</code></td><td><code>html`...`</code></td><td>Write your component’s HTML as a template literal. Values you interpolate are escaped automatically to prevent XSS. Nested <code>html</code> fragments are passed through as-is. Return this from <code>render()</code>.</td></tr><tr><td><code>nothing</code></td><td><code>nothing</code></td><td>Use this in conditional expressions when you want to render nothing. Safer than <code>&quot;&quot;</code> or <code>false</code>, which can produce unexpected output.</td></tr><tr><td><code>unsafeHTML</code></td><td><code>unsafeHTML(str)</code></td><td>Renders a plain string as raw HTML, skipping automatic escaping. Only use this for content you fully control.</td></tr></tbody></table><h3 id="component-options" tabindex="-1">Component Options <a class="header-anchor" href="#component-options" aria-label="Permalink to &quot;Component Options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>tagName</code></td><td><code>string</code></td><td>The HTML tag name for this component (e.g. <code>&quot;elena-button&quot;</code>). Required for <code>define()</code> to register the element.</td></tr><tr><td><code>props</code></td><td><code>(string | { name: string, reflect?: boolean })[]</code></td><td>The list of props this component accepts. Each prop stays in sync with its matching HTML attribute. Use <code>{ name, reflect: false }</code> to keep a prop JS-only without writing it back to the attribute.</td></tr><tr><td><code>events</code></td><td><code>string[]</code></td><td>Events to forward from the inner element up to the host (e.g. <code>[&quot;click&quot;, &quot;focus&quot;, &quot;blur&quot;]</code>).</td></tr><tr><td><code>element</code></td><td><code>string</code></td><td>A CSS selector for the inner element that <code>this.element</code> points to (e.g. <code>&quot;.inner&quot;</code>, <code>&quot;button&quot;</code>). Defaults to the first child element when omitted.</td></tr><tr><td><code>shadow</code></td><td><code>&quot;open&quot; | &quot;closed&quot;</code></td><td>Attaches a shadow root to the host element. Elena renders into the shadow root instead of the host.</td></tr><tr><td><code>styles</code></td><td><code>CSSStyleSheet | string | (CSSStyleSheet | string)[]</code></td><td>One or more stylesheets to adopt into the shadow root. Only applies when <code>shadow</code> is also set.</td></tr></tbody></table><h3 id="host-attributes" tabindex="-1">Host Attributes <a class="header-anchor" href="#host-attributes" aria-label="Permalink to &quot;Host Attributes&quot;">​</a></h3><p>Attributes that Elena adds to the host element automatically. These are not JS properties, they appear in the DOM and can be targeted in CSS.</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Description</th></tr></thead><tbody><tr><td><code>hydrated</code></td><td>Added to the host element after the first render completes. Use <code>:not([hydrated])</code> in CSS to style the element before JavaScript runs, and remove those styles once it hydrates.</td></tr></tbody></table><h3 id="instance-properties" tabindex="-1">Instance Properties <a class="header-anchor" href="#instance-properties" aria-label="Permalink to &quot;Instance Properties&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>text</code></td><td><code>string</code></td><td>The text content of the element. Elena reads this from the element’s children before the first render. Setting it later triggers a re-render. When you need to dynamically update this, pass text via a property instead of children.</td></tr><tr><td><code>element</code></td><td><code>HTMLElement | null</code></td><td>A reference to the inner element, resolved after the first render using the <code>element</code> option.</td></tr></tbody></table><h3 id="lifecycle-methods" tabindex="-1">Lifecycle Methods <a class="header-anchor" href="#lifecycle-methods" aria-label="Permalink to &quot;Lifecycle Methods&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>connectedCallback()</code></td><td>Runs when the element is added to the page. Sets up props, captures text content, renders, and wires up events.</td></tr><tr><td><code>willUpdate()</code></td><td>Runs before every render, including the first. Override to compute derived state before the template evaluates.</td></tr><tr><td><code>render()</code></td><td>Returns the HTML for this component as an <code>html</code> template. Called on connect and whenever the component needs re-rendering. Omit this method entirely for components that don’t render their own HTML.</td></tr><tr><td><code>firstUpdated()</code></td><td>Runs once after the first render. <code>this.element</code> is available here. Override to run one-time setup that requires the DOM.</td></tr><tr><td><code>updated()</code></td><td>Runs after every render, including the first. <code>this.element</code> is available here. Override to react to changes after the DOM is updated. On first connect, <code>firstUpdated()</code> runs before <code>updated()</code>.</td></tr><tr><td><code>requestUpdate()</code></td><td>Manually schedules a re-render. Use when Elena can’t detect a change automatically, e.g. when mutating an object or array in place. Returns nothing, use <code>updateComplete</code> to wait for the render to finish.</td></tr><tr><td><code>disconnectedCallback()</code></td><td>Runs when the element is removed from the page. Cleans up event listeners.</td></tr><tr><td><code>adoptedCallback()</code></td><td>Runs when the element is moved to a new document via <code>document.adoptNode()</code>. Override to react to document changes.</td></tr><tr><td><code>attributeChangedCallback()</code></td><td>Runs when an observed attribute changes. Updates the matching JS property and triggers a re-render.</td></tr></tbody></table><h3 id="instance-promises" tabindex="-1">Instance Promises <a class="header-anchor" href="#instance-promises" aria-label="Permalink to &quot;Instance Promises&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>updateComplete</code></td><td><code>Promise&lt;void&gt;</code></td><td>Resolves after the next pending render finishes. Use it to wait for the DOM to settle before reading it. Resolves immediately if no render is pending.</td></tr></tbody></table><h3 id="static-methods" tabindex="-1">Static Methods <a class="header-anchor" href="#static-methods" aria-label="Permalink to &quot;Static Methods&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>ClassName.define()</code></td><td>Registers the component with the browser using <code>tagName</code> option. Call this once after defining your class. Does nothing in non-browser environments.</td></tr><tr><td><code>ClassName.observedAttributes</code></td><td>The list of attributes the browser should watch for changes, built from <code>props</code> option plus the built-in <code>text</code> attribute.</td></tr></tbody></table><h3 id="error-codes" tabindex="-1">Error Codes <a class="header-anchor" href="#error-codes" aria-label="Permalink to &quot;Error Codes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Error</th><th>Explanation</th></tr></thead><tbody><tr><td><code style="white-space:nowrap;">&quot;text&quot; is reserved.</code></td><td>You included <code>&quot;text&quot;</code> in <code>static props</code>. Elena manages <code>text</code> as a built-in reactive property, remove it from the props array to fix the error.</td></tr><tr><td><code style="white-space:nowrap;">define() without a tagName.</code></td><td><code>ClassName.define()</code> was called but <code>static tagName</code> is not set on the class. Add a <code>static tagName</code> before calling <code>define()</code>.</td></tr><tr><td><code>Element not found.</code></td><td>The CSS selector in <code>static element</code> did not match any element in the rendered output. Check that the selector is correct and that <code>render()</code> produces a matching element.</td></tr><tr><td><code>Cannot add events.</code></td><td><code>static events</code> is set but no inner element reference could be resolved. Either add a <code>render()</code> that produces an inner element, or check your <code>static element</code> selector.</td></tr><tr><td><code style="white-space:nowrap;">Prop &quot;&lt;name&gt;&quot; has no default.</code></td><td>An attribute changed for a prop that has no corresponding instance field default. Add a default value (e.g. <code>myProp = &quot;&quot;</code>) to the component class body.</td></tr><tr><td><code>Invalid JSON: &lt;value&gt;</code></td><td>An <code>Array</code> or <code>Object</code> prop received an attribute value that could not be parsed as JSON. Check that the attribute value is valid JSON. The prop will be set to <code>null</code>.</td></tr><tr><td><code>Cannot sync attrs.</code></td><td><code>syncAttribute()</code> was called with a null element reference. This usually means the inner element was not found before attribute sync ran. Check your <code>static element</code> selector.</td></tr></tbody></table><h2 id="elenajs-bundler" tabindex="-1"><code>@elenajs/bundler</code> <a class="header-anchor" href="#elenajs-bundler" aria-label="Permalink to &quot;`@elenajs/bundler`&quot;">​</a></h2><h3 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">elena</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">elena</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> watch</span></span></code></pre></div><h3 id="cli-flags" tabindex="-1">CLI Flags <a class="header-anchor" href="#cli-flags" aria-label="Permalink to &quot;CLI Flags&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Description</th></tr></thead><tbody><tr><td><code>--config &lt;path&gt;</code></td><td>Path to a config file. Defaults to <code>elena.config.mjs</code> or <code>elena.config.js</code> in the project root.</td></tr></tbody></table><h3 id="elena-config-mjs-options" tabindex="-1"><code>elena.config.mjs</code> Options <a class="header-anchor" href="#elena-config-mjs-options" aria-label="Permalink to &quot;`elena.config.mjs` Options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>input</code></td><td><code>string</code></td><td><code>&quot;src&quot;</code></td><td>The folder containing your component source files.</td></tr><tr><td><code>output.dir</code></td><td><code>string</code></td><td><code>&quot;dist&quot;</code></td><td>Where to write the compiled output.</td></tr><tr><td><code>output.format</code></td><td><code>string</code></td><td><code>&quot;esm&quot;</code></td><td>JavaScript module format for the output files.</td></tr><tr><td><code>output.sourcemap</code></td><td><code>boolean</code></td><td><code>true</code></td><td>Whether to generate source maps alongside the output.</td></tr><tr><td><code>bundle</code></td><td><code>string | false</code></td><td><code>&quot;src/index.js&quot;</code></td><td>Entry point for a single combined output file. Elena will look for <code>src/index.ts</code> automatically if no <code>.js</code> file is found. Set to <code>false</code> to skip the bundle entirely.</td></tr><tr><td><code>plugins</code></td><td><code>Plugin[]</code></td><td><code>[]</code></td><td>Extra Rollup plugins to include in the build, added after Elena’s built-in ones.</td></tr><tr><td><code>analyze</code></td><td><code>object | false</code></td><td><code>{ plugins: [] }</code></td><td>CEM analysis options. Set to <code>false</code> to skip Custom Elements Manifest generation, TypeScript declarations, and JSX types entirely.</td></tr><tr><td><code>analyze.plugins</code></td><td><code>Plugin[]</code></td><td><code>[]</code></td><td>Extra plugins for the Custom Elements Manifest generation step.</td></tr><tr><td><code>target</code></td><td><code>string | string[] | false</code></td><td><code>false</code></td><td>Browserslist target(s) for transpilation. When set, enables syntax transforms (e.g. class fields, optional chaining) via <code>@babel/preset-env</code> to widen browser support. Example: <code>[&quot;chrome 71&quot;, &quot;firefox 69&quot;, &quot;safari 12.1&quot;]</code>.</td></tr><tr><td><code>terser</code></td><td><code>object</code></td><td><code>{ ecma: 2020, module: true }</code></td><td>Custom Terser minifier options, merged with the defaults.</td></tr></tbody></table><h2 id="elenajs-cli" tabindex="-1"><code>@elenajs/cli</code> <a class="header-anchor" href="#elenajs-cli" aria-label="Permalink to &quot;`@elenajs/cli`&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> elena-create</span></span></code></pre></div><p>Starts an interactive prompt that walks you through creating a new Elena component. No flags needed, it asks you everything it needs:</p><table tabindex="0"><thead><tr><th>Prompt</th><th>Options</th></tr></thead><tbody><tr><td>Component name</td><td>Any valid kebab-case custom element name (e.g. <code>my-button</code>)</td></tr><tr><td>Component features</td><td>Props, events, methods, CSS custom properties, encapsulation reset, SSR, and code comments (each optional)</td></tr><tr><td>Language</td><td>JavaScript, TypeScript, or single-file HTML</td></tr><tr><td>Output directory</td><td>Where to write the generated files</td></tr></tbody></table><p>The generated files follow all Elena authoring patterns, including JSDoc annotations and <code>@scope</code> CSS.</p><h2 id="elenajs-ssr" tabindex="-1"><code>@elenajs/ssr</code> <a class="header-anchor" href="#elenajs-ssr" aria-label="Permalink to &quot;`@elenajs/ssr`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>register</code></td><td><code>register(...components)</code></td><td>Tell the SSR renderer which component classes to expand. Each class must have <code>tagName</code> option set. Call this before <code>ssr()</code>.</td></tr><tr><td><code>ssr</code></td><td><code>ssr(html)</code></td><td>Takes an HTML string, expands any registered components into full HTML, and returns the result. The rest of the HTML tags are left as-is.</td></tr></tbody></table><h2 id="elenajs-plugin-rollup-css" tabindex="-1"><code>@elenajs/plugin-rollup-css</code> <a class="header-anchor" href="#elenajs-plugin-rollup-css" aria-label="Permalink to &quot;`@elenajs/plugin-rollup-css`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>cssPlugin</code></td><td><code>cssPlugin(srcDir)</code></td><td>Copies and minifies each <code>.css</code> file from <code>srcDir</code> into the output folder as individual files.</td></tr><tr><td><code>cssBundlePlugin</code></td><td><code>cssBundlePlugin(srcDir, fileName)</code></td><td>Combines all <code>.css</code> files from <code>srcDir</code> into a single minified file named <code>fileName</code>. CSS files resolved by <code>cssModuleScriptPlugin</code> are automatically excluded.</td></tr><tr><td><code>cssModuleScriptPlugin</code></td><td><code>cssModuleScriptPlugin()</code></td><td>Handles CSS Module Script imports (<code>with { type: &quot;css&quot; }</code>). Reads and minifies the CSS file, then returns a JS module that constructs and exports a <code>CSSStyleSheet</code> for Shadow DOM adoption.</td></tr><tr><td><code>cssStaticStylesPlugin</code></td><td><code>cssStaticStylesPlugin()</code></td><td>Finds <code>static styles</code> class fields with template literal values and minifies the CSS inside them.</td></tr><tr><td><code>minifyCss</code></td><td><code>minifyCss(css, filename?)</code></td><td>Minifies a CSS string using Lightning CSS.</td></tr></tbody></table><h2 id="elenajs-plugin-cem-define" tabindex="-1"><code>@elenajs/plugin-cem-define</code> <a class="header-anchor" href="#elenajs-plugin-cem-define" aria-label="Permalink to &quot;`@elenajs/plugin-cem-define`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>elenaDefinePlugin</code></td><td><code>elenaDefinePlugin()</code></td><td>CEM plugin that reads <code>tagName</code> option from each Elena component class and registers it in the Custom Elements Manifest.</td></tr></tbody></table><h2 id="elenajs-plugin-cem-tag" tabindex="-1"><code>@elenajs/plugin-cem-tag</code> <a class="header-anchor" href="#elenajs-plugin-cem-tag" aria-label="Permalink to &quot;`@elenajs/plugin-cem-tag`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>elenaTagPlugin</code></td><td><code>elenaTagPlugin(jsdocTag)</code></td><td>CEM plugin that copies a custom JSDoc tag from each component’s documentation comment into the Custom Elements Manifest. <code>jsdocTag</code> is the tag name without the <code>@</code> (e.g. <code>&quot;status&quot;</code> for <code>@status</code>, <code>&quot;displayName&quot;</code> for <code>@displayName</code>). Call it once per tag you want to extract.</td></tr></tbody></table><h2 id="elenajs-plugin-cem-typescript" tabindex="-1"><code>@elenajs/plugin-cem-typescript</code> <a class="header-anchor" href="#elenajs-plugin-cem-typescript" aria-label="Permalink to &quot;`@elenajs/plugin-cem-typescript`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>elenaTypeScriptPlugin</code></td><td><code>elenaTypeScriptPlugin(options?)</code></td><td>CEM plugin that generates a <code>.d.ts</code> type file for each component (e.g. <code>button.d.ts</code> alongside <code>button.js</code>), including typed props and event handler fields. Also adds the built-in <code>text</code> prop to every component’s type.</td></tr></tbody></table><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>outdir</code></td><td><code>string</code></td><td><code>&quot;dist&quot;</code></td><td>Where to write the generated <code>.d.ts</code> TypeScript types.</td></tr></tbody></table>',44)])])}const m=t(n,[["render",r]]);export{p as __pageData,m as default};
